Console.WriteLine($"ExecuteAsync signature: {executeAsync}");
Console.WriteLine($"  Return type: {executeAsync?.ReturnType}");
Console.WriteLine($"  Parameters:");
foreach (var p in executeAsync?.GetParameters() ?? Array.Empty<ParameterInfo>())
